import pyautogui; 
try:
    import pyperclip
except ImportError:
    import subprocess
    subprocess.run('echo "osworld-public-evaluation" | sudo -S apt-get install -y xclip xsel', shell=True, check=True)
    subprocess.check_call([subprocess.sys.executable, '-m', 'pip', 'install', 'pyperclip'])
    import pyperclip

pyautogui.click(1000, 404); pyperclip.copy('The purpose of the tutorial is to facilitate in-depth discussions on a more specific issue related to our lectures. Discussions play an important role in learning as it helps to deepen your understanding and develop your own ideas. Besides this, if you can explain something to others clearly, then you really understand it. If you can’t, you don’t! So, the discussion is also an effective way for you to examine how much you have understood in class. The harvest of our tutorials largely depends on your active participation and contribution. Thus, be proactive and talkative!'); pyautogui.hotkey('ctrl', 'v'); pyautogui.press('enter');

